extra.modelCss:
/* Página de aula (layout pro) */

:root {
  --bg: #0b0f19;
  --panel: #111827;
  --text: #e5e7eb;
  --muted: #9ca3af;
  --accent: #60a5fa;
  --border: rgba(255, 255, 255, 0.10);
  --danger: #ef4444;
  --success: #22c55e;
  --radius: 14px;
}

.lesson-page {
  padding: 16px 0;
}

.lesson-layout {
  display: grid;
  grid-template-columns: 1fr;
  gap: 16px;
  align-items: start;
}

@media (min-width: 1024px) {
  .lesson-layout {
    grid-template-columns: 1fr 320px;
    gap: 24px;
  }
}

.lesson-main {
  display: grid;
  gap: 16px;
}

.prose {
  max-width: 65ch;
}

.card {
  background: var(--panel);
  border: 1px solid var(--border);
  border-radius: var(--radius);
}

.card-inner {
  padding: 16px;
  display: grid;
  gap: 12px;
}

.lesson-aside {
  display: grid;
  gap: 16px;
}

.toc {
  position: static;
}

@media (min-width: 1024px) {
  .toc {
    position: sticky;
    top: 16px;
  }
}

.toc__title {
  font-weight: 800;
  margin: 0;
}

.toc__list {
  list-style: none;
  padding: 0;
  margin: 0;
  display: grid;
  gap: 8px;
}

.toc__link {
  display: block;
  padding: 10px 12px;
  border-radius: 12px;
  color: var(--text);
  text-decoration: none;
  border: 1px solid transparent;
}

.toc__link:hover {
  background: rgba(255, 255, 255, 0.04);
}

.toc__link:focus-visible {
  outline: 3px solid var(--accent);
  outline-offset: 3px;
}

.exercise {
  display: grid;
  gap: 12px;
}

.editor {
  width: 100%;
  min-height: 180px;
  padding: 12px;
  border-radius: 12px;
  border: 1px solid var(--border);
  background: rgba(255, 255, 255, 0.02);
  color: var(--text);
  font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace;
  line-height: 1.5;
  resize: vertical;
}

.editor:focus-visible {
  outline: 3px solid var(--accent);
  outline-offset: 2px;
  border-color: rgba(96, 165, 250, 0.60);
}

.feedback {
  padding: 10px 12px;
  border-radius: 12px;
  border: 1px solid var(--border);
  background: rgba(255, 255, 255, 0.02);
}

.feedback.success {
  border-color: rgba(34, 197, 94, 0.35);
  background: rgba(34, 197, 94, 0.10);
}

.feedback.error {
  border-color: rgba(239, 68, 68, 0.35);
  background: rgba(239, 68, 68, 0.10);
}

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  padding: 10px 14px;
  border-radius: 12px;
  border: 1px solid transparent;
  font-weight: 700;
  cursor: pointer;
}

.btn.primary {
  background: var(--accent);
  color: #0b0f19;
}

.btn.ghost {
  background: transparent;
  color: var(--text);
  border-color: var(--border);
}

.btn:focus-visible {
  outline: 3px solid var(--accent);
  outline-offset: 3px;
}

.stack {
  display: grid;
  gap: 16px;
}
